      result += ch; i++;
    }
  }
  return result;
}
cleaned = fixJsonStrings(cleaned);

cleaned = cleaned.replace(/,\s*$/, '');
const ob = (cleaned.match(/{/g)||[]).length, cb = (cleaned.match(/}/g)||[]).length;
const oB = (cleaned.match(/\[/g)||[]).length, cB = (cleaned.match(/\]/g)||[]).length;
for (let i = 0; i < oB - cB; i++) cleaned += ']';
for (let i = 0; i < ob - cb; i++) cleaned += '}';

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Cannot parse JSON from LLM. Error: ' + e.message + '\nRaw (800): ' + cleaned.substring(0, 800));
}

const requirements = parsed?.requirements;
if (!Array.isArray(requirements) || requirements.length === 0) {
  throw new Error('LLM response missing requirements array or empty.');
}

const clarificationQuestions = Array.isArray(parsed?.clarificationQuestions)
  ? parsed.clarificationQuestions
  : [];

const validTypes = ['functional', 'non-functional', 'security', 'performance', 'constraint'];
const asJsonArrayString = (v, def) => {
  if (v === null || v === undefined) return def;
  if (typeof v === 'string') {
    const s = v.trim();
    if (!s) return def;
    try { JSON.parse(s); return s; } catch { return JSON.stringify([s]); }
  }
  if (Array.isArray(v)) return JSON.stringify(v);
