requirements.forEach((r, i) => {
  if (!r.requirementCode) r.requirementCode = `REQ-${String(i + 1).padStart(3, '0')}`;
  if (!r.title) throw new Error(`Requirement index ${i} missing title.`);
  if (!r.description) r.description = r.title;
  r.type = validTypes.includes(String(r.type).toLowerCase())
    ? String(r.type).toLowerCase()
