  r.testableConstraints = asJsonArrayString(r.testableConstraints, '[]');
  r.assumptions = asJsonArrayString(r.assumptions, '[]');
  r.ambiguities = asJsonArrayString(r.ambiguities, '[]');
  r.confidenceScore = typeof r.confidenceScore === 'number'
