  r.mappedEndpointPath = r.mappedEndpointPath ?? null;
});

clarificationQuestions.forEach((q, i) => {
  if (!q.requirementCode) throw new Error(`ClarificationQuestion index ${i} missing requirementCode.`);
  if (!q.question) throw new Error(`ClarificationQuestion index ${i} missing question.`);
  q.ambiguitySource = q.ambiguitySource ?? q.question;
  q.isCritical = q.isCritical === true;
  q.suggestedOptions = asJsonArrayString(q.suggestedOptions, null);
});

return [{
  json: {
    requirements,
    clarificationQuestions,
    model: parsed.model ?? 'llama-3.3-70b-versatile',
    tokensUsed: parsed.tokensUsed ?? 0
  }
}];

