}

return [{
  json: {
    srsDocumentId: body.srsDocumentId,
    jobId: body.jobId,
    requirementsToRefine: body.requirementsToRefine
  }
}];

const rawInput = $input.first().json.body ?? $input.first().json;
const body = typeof rawInput === 'string' ? JSON.parse(rawInput) : rawInput;

const endpoints = body.endpoints;
if (!Array.isArray(endpoints) || endpoints.length === 0) {
  throw new Error('Payload must contain non-empty endpoints array.');
}

const promptConfig = body.promptConfig ?? {};
if (!promptConfig.systemPrompt || !String(promptConfig.systemPrompt).trim()) {
  throw new Error('Payload missing promptConfig.systemPrompt from BE.');
}
if (!promptConfig.taskInstruction || !String(promptConfig.taskInstruction).trim()) {
  throw new Error('Payload missing promptConfig.taskInstruction from BE.');
}
if (!promptConfig.rules || !String(promptConfig.rules).trim()) {
  throw new Error('Payload missing promptConfig.rules from BE.');
}
if (!promptConfig.responseFormat || !String(promptConfig.responseFormat).trim()) {
  throw new Error('Payload missing promptConfig.responseFormat from BE.');
}

const algorithmProfile = body.algorithmProfile ?? {};

return [{
  json: {
    testSuiteId: body.testSuiteId ?? '',
    promptConfig,
    algorithmProfile,
    srsContext: body.srsContext ?? null,
    endpoints
  }
}];

const { promptConfig, endpoints, algorithmProfile, srsContext } = $input.first().json;

const promptBlocks = endpoints
  .map((ep, i) => {
    const combined = String(ep?.prompt?.combinedPrompt || '').trim();
    if (!combined) {
      throw new Error(`Endpoint ${i + 1} (ID=${ep?.endpointId || 'unknown'}) is missing prompt.combinedPrompt from BE.`);
    }

    return [
      `### Endpoint ${i + 1} [ID=${ep.endpointId}] ${ep.httpMethod} ${ep.path}`,
      combined
    ].join('\n');
  });

const systemPrompt = String(promptConfig.systemPrompt || '').trim();
const taskInstruction = String(promptConfig.taskInstruction || '').trim();
const rules = String(promptConfig.rules || '').trim();
const responseFormat = String(promptConfig.responseFormat || '').trim();

if (!systemPrompt || !taskInstruction || !rules || !responseFormat) {
  throw new Error('promptConfig from BE is incomplete. Required: systemPrompt, taskInstruction, rules, responseFormat.');
}

const enabledFlags = Object.entries(algorithmProfile || {})
  .filter(([, value]) => value === true)
  .map(([key]) => `- ${key}`);

const algorithmGuidance = enabledFlags.length > 0
  ? [
      '=== ALGORITHM PROFILE FROM BE (ENABLED FLAGS) ===',
      enabledFlags.join('\n'),
      'Apply these generation strategies while producing scenarios.'
    ].join('\n')
  : [
      '=== ALGORITHM PROFILE FROM BE (ENABLED FLAGS) ===',
      '- none',
      'Use promptConfig instructions as the primary strategy.'
    ].join('\n');

// Build SRS section when BE provides it
let srsSection = '';
if (srsContext && (srsContext.content || (Array.isArray(srsContext.requirements) && srsContext.requirements.length > 0))) {
  const parts = [`=== SRS DOCUMENT: ${srsContext.documentTitle || 'Untitled'} ===`];
  if (srsContext.content) { parts.push(srsContext.content); }
  if (Array.isArray(srsContext.requirements) && srsContext.requirements.length > 0) {
    parts.push('--- REQUIREMENTS ---');
    for (const req of srsContext.requirements) {
      parts.push(`[${req.code}] ${req.title}`);
      if (req.endpointId) {
        parts.push(`EndpointId: ${req.endpointId}`);
      }
      if (Array.isArray(req.testableConstraints) && req.testableConstraints.length > 0) {
        parts.push('Constraints:');
        for (const c of req.testableConstraints) {
          const constraint = String(c?.constraint || '').trim();
          if (!constraint) continue;
          const outcome = String(c?.expectedOutcome || '').trim();
          const priority = String(c?.priority || '').trim();
          const extras = [
            outcome ? `expectedOutcome=${outcome}` : null,
            priority ? `priority=${priority}` : null
          ].filter(Boolean).join(', ');
          parts.push(`- ${constraint}${extras ? ` (${extras})` : ''}`);
        }
      }
      const description = String(req.description || '').trim();
      if (description) {
        parts.push(description);
      }
      parts.push('');
    }
  }
  srsSection = parts.join('\n');
}

const userPrompt = [
  taskInstruction,
  algorithmGuidance,
  ...(srsSection ? ['=== SRS REQUIREMENTS (align generated scenarios to these) ===', srsSection] : []),
  '=== BE GENERATED ENDPOINT PROMPTS (PRIMARY INPUT) ===',
  promptBlocks.join('\n\n'),
  rules,
  responseFormat
].join('\n\n');

return [{ json: { systemPrompt, userPrompt } }];

// Safety net: if LLM didn't use {{tcUniqueId}} in fields that need uniqueness, patch them.
// Generic — works for any field name / any project / any domain. No URL-pattern matching.
function patchBodyForUniqueness(body) {
  if (!body || typeof body !== 'string') return body;
  let obj;
  try { obj = JSON.parse(body); } catch { return body; }
  let changed = false;

  // Regex for a valid email address (\\w = \w in JS inside JSON string)
  const emailRe = /^([\w.+-]+)@([\w.-]+)$/;
  // Field names that typically require a unique value per run
  const uniqueFieldRe = /^(email|username|user_name|user|name|code|slug|phone|mobile|ref|reference|sku|handle|login|nickname|tag)$/i;

  function walk(node) {
    if (!node || typeof node !== 'object') return;
    for (const key of Object.keys(node)) {
      const val = node[key];
      if (typeof val === 'string') {
        const p = patchValue(key, val);
        if (p !== val) { node[key] = p; changed = true; }
      } else if (typeof val === 'object') { walk(val); }
    }
  }

  function patchValue(key, val) {
    // Already a placeholder — VariableResolver will handle it
    if (val.includes('{{')) return val;
    // Already uniquified (ends with _xxxxxxxx 8-char hex)
    if (/_[a-f0-9]{8}$/.test(val.toLowerCase())) return val;

    // Email fields: patch local part with _{{tcUniqueId}} suffix
    const emailMatch = val.match(emailRe);
    if (emailMatch) {
      const local = emailMatch[1].toLowerCase();
      const domain = emailMatch[2];
      // Only patch if it looks synthetic (not a real runtime value from a prior test)
      const looksStatic = /^(test|user|demo|sample|qa|auto|register|new|admin|foo|bar|fake|dummy|temp)/.test(local)
        || domain.startsWith('example.') || domain === 'test.com' || domain === 'mailtest.com';
      if (looksStatic) {
        console.warn('[patchBodyForUniqueness] Patching bare email "' + val + '" in field "' + key + '"');
        return local + '_{{tcUniqueId}}@' + domain;
      }
      return val;
    }

    // Non-email unique fields: append _{{tcUniqueId}} if value looks like a static placeholder
    if (uniqueFieldRe.test(key)) {
      const looksStatic = /^(test|user|demo|sample|qa|auto|my|new|admin|foo|bar|fake|dummy|temp|default)[_-]?/.test(val.toLowerCase());
      if (looksStatic) {
        console.warn('[patchBodyForUniqueness] Patching bare unique field "' + key + '" value "' + val + '"');
        return val + '_{{tcUniqueId}}';
      }
    }
    return val;
  }

  walk(obj);
  return changed ? JSON.stringify(obj) : body;
}

// ━━━ Parse LLM response ━━━
const response = $input.first().json;

const rawContent =
  response?.output ??
  response?.choices?.[0]?.message?.content ??
  null;

