const fencedMatch = cleaned.match(/```(?:json)?\s*([\s\S]*?)\s*```/i);
if (fencedMatch?.[1]) {
  cleaned = fencedMatch[1].trim();
} else {
  cleaned = cleaned.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '').trim();
}
cleaned = cleaned.replace(/```/g, '').trim();

// Extract JSON object boundary
const firstBrace = cleaned.indexOf('{');
const lastBrace  = cleaned.lastIndexOf('}');
if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
  cleaned = cleaned.slice(firstBrace, lastBrace + 1);
}

// Fix trailing commas before ] or }
cleaned = cleaned.replace(/,\s*([}\]])/g, '$1');

// Fix unescaped control chars inside strings
function fixControlChars(s) {
  let result = '', inString = false, i = 0;
  while (i < s.length) {
    const ch = s[i];
    if (inString) {
      if (ch === '\\') { result += ch; i++; if (i < s.length) { result += s[i]; i++; } continue; }
      if (ch === '"') { inString = false; result += ch; i++; continue; }
      if (ch === '\n') { result += '\\n'; i++; continue; }
      if (ch === '\r') { result += '\\r'; i++; continue; }
      if (ch === '\t') { result += '\\t'; i++; continue; }
      result += ch; i++;
    } else {
      if (ch === '"') inString = true;
      result += ch; i++;
    }
  }
  return result;
}
cleaned = fixControlChars(cleaned);

// Close unclosed brackets (handles LLM truncation)
cleaned = cleaned.replace(/,\s*$/, '');
const ob = (cleaned.match(/{/g)||[]).length, cb = (cleaned.match(/}/g)||[]).length;
const oB = (cleaned.match(/\[/g)||[]).length, cB = (cleaned.match(/\]/g)||[]).length;
for (let i = 0; i < oB - cB; i++) cleaned += ']';
for (let i = 0; i < ob - cb; i++) cleaned += '}';

// ── Fallback: extract individual complete scenario objects ──
// Used when primary JSON.parse fails (e.g. unescaped quotes mid-string,
// truncated JSON with partial object at end, etc.)
function extractCompleteScenarios(text) {
  const arrM = text.match(/"scenarios"\s*:\s*\[/);
  if (!arrM) throw new Error('Khong tim thay mang scenarios trong JSON.');
  const arrStart = arrM.index + arrM[0].length;
  let depth = 0, objStart = -1;
  const items = [];
  let i = arrStart;
  while (i < text.length) {
    const c = text[i];
    // Skip over string literals to avoid false bracket-depth counting
    if (c === '"') {
      i++;
      while (i < text.length) {
        if (text[i] === '\\') { i += 2; continue; }
        if (text[i] === '"') break;
        i++;
      }
      i++;
      continue;
    }
    if (c === '{') {
      if (depth === 0) objStart = i;
      depth++;
    } else if (c === '}') {
      depth--;
      if (depth === 0 && objStart !== -1) {
        const objText = text.slice(objStart, i + 1);
        try {
          const obj = JSON.parse(fixControlChars(objText));
          items.push(obj);
        } catch (_) { /* skip malformed individual objects */ }
        objStart = -1;
      }
    } else if (c === ']' && depth === 0) {
      break;
    }
    i++;
  }
  if (items.length === 0) throw new Error('Khong trich xuat duoc scenario nao hop le.');
  return { scenarios: items, model: 'unknown', tokensUsed: 0 };
}

// ── Primary parse → fallback extractor ──
let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e1) {
  try {
    parsed = extractCompleteScenarios(cleaned);
    // Log recovery info (visible in n8n execution log)
    console.warn('[ParseBoundaryResponse] Used fallback extractor, recovered ' + parsed.scenarios.length + ' scenarios. Primary JSON.parse error: ' + e1.message.substring(0, 120));
  } catch (e2) {
    throw new Error('Khong parse duoc JSON tu LLM. Error: ' + e1.message + '\nRaw (800): ' + cleaned.substring(0, 800));
  }
}

const scenarios = parsed?.scenarios;
if (!Array.isArray(scenarios) || scenarios.length === 0) {
  throw new Error('LLM response thieu mang scenarios hoac rong.');
}

// Normalize scenarios
scenarios.forEach((s, i) => {
  if (!s?.endpointId) throw new Error('Scenario index ' + i + ' thieu endpointId.');
  s.scenarioName = String(s.scenarioName ?? ('Scenario ' + (i + 1)));
  s.description  = String(s.description  ?? '');
  // Respect whatever testType the LLM returned; only fall back when truly absent
  const rawType = String(s.testType ?? '').trim();
  const normType = rawType.replace(/[_\s-]/g, '').toLowerCase();
  s.testType = normType === 'happypath' ? 'HappyPath' : normType === 'boundary' ? 'Boundary' : normType === 'negative' ? 'Negative' : (rawType || 'Negative');
  s.priority     = String(s.priority     ?? 'Medium');
  s.tags         = Array.isArray(s.tags) ? s.tags : [];
  s.variables    = Array.isArray(s.variables) ? s.variables : [];
  s.coveredRequirementCodes = Array.isArray(s.coveredRequirementCodes)
    ? s.coveredRequirementCodes.map(String).filter(c => c.trim())
    : [];

  s.request = s.request ?? {};
  s.request.httpMethod  = String(s.request.httpMethod ?? 'GET');
  s.request.url         = String(s.request.url        ?? '/');
  s.request.bodyType    = String(s.request.bodyType   ?? 'None');
  s.request.timeout     = Number(s.request.timeout    ?? 30000);
  s.request.headers     = s.request.headers     ?? null;
  s.request.pathParams  = s.request.pathParams  ?? null;
  s.request.queryParams = s.request.queryParams ?? null;
  if (s.request.body !== null && s.request.body !== undefined && typeof s.request.body !== 'string') {
    s.request.body = JSON.stringify(s.request.body);
  }

  s.expectation = s.expectation ?? {};
  if (!Array.isArray(s.expectation.expectedStatus)) {
    s.expectation.expectedStatus = [400];
  }
  s.expectation.bodyContains    = s.expectation.bodyContains    ?? null;
  s.expectation.bodyNotContains = s.expectation.bodyNotContains ?? null;
  s.expectation.jsonPathChecks  = (s.expectation.jsonPathChecks && typeof s.expectation.jsonPathChecks === 'object' && Object.keys(s.expectation.jsonPathChecks).length > 0)
    ? s.expectation.jsonPathChecks
    : null;
});

function normalizeExpectationToken(value) {
  if (value === null || value === undefined) return value;
  if (typeof value !== 'string') return value;
  const raw = value.trim();
  if (!raw) return value;
  const lower = raw.toLowerCase();
  const collapsed = lower.replace(/[\s_-]+/g, '');
  if (collapsed === 'nonempty' || collapsed === 'notempty' || collapsed === 'nonblank' || collapsed === 'notblank') {
    return 'non-empty';
  }
  if (collapsed === 'notnull' || collapsed === 'nonnull') {
    return 'not null';
  }
  if (collapsed === 'exists' || collapsed === 'exist' || collapsed === 'present') {
    return 'present';
  }
  if (lower.startsWith('type:') || lower.startsWith('type=')) {
    const t = lower.slice(5).trim();
    if (['string', 'number', 'boolean', 'array', 'object', 'uuid', 'guid', 'datetime', 'date-time', 'timestamp'].includes(t)) {
      if (t === 'guid') return 'uuid';
      if (t === 'date-time' || t === 'timestamp') return 'datetime';
      return t;
    }
  }
  if (lower.startsWith('format:') || lower.startsWith('format=')) {
    const t = lower.slice(7).trim();
    if (['string', 'number', 'boolean', 'array', 'object', 'uuid', 'guid', 'datetime', 'date-time', 'timestamp'].includes(t)) {
      if (t === 'guid') return 'uuid';
      if (t === 'date-time' || t === 'timestamp') return 'datetime';
      return t;
    }
  }
  return value;
}

function normalizeJsonPathChecks(s) {
  const checks = s.expectation?.jsonPathChecks;
  if (!checks || typeof checks !== 'object') return;
  for (const path of Object.keys(checks)) {
    if (typeof checks[path] === 'string') {
      checks[path] = normalizeExpectationToken(checks[path]);
    }
  }
}
scenarios.forEach(normalizeJsonPathChecks);

// Apply uniqueness safety net to all scenario bodies
scenarios.forEach(s => { s.request.body = patchBodyForUniqueness(s.request.body); });

// Sync jsonPathChecks with body: if LLM used different email/unique-field values in
// assertions vs body (common LLM inconsistency), override assertions to match the body.
// Also apply patchBodyForUniqueness to bare values inside jsonPathChecks.
function syncJsonPathChecks(s) {
  const checks = s.expectation?.jsonPathChecks;
  if (!checks || typeof checks !== 'object') return;

  // Extract top-level string fields from the (already-patched) request body
  let bodyFields = {};
  if (s.request?.body && typeof s.request.body === 'string') {
    try { bodyFields = JSON.parse(s.request.body); } catch { bodyFields = {}; }
  }

  // Regex: path ends with a known unique field name (case-insensitive)
  const uniquePathRe = /(?:^|\.)(?:email|username|user_name|name|code|slug|phone|mobile|ref|sku|handle|login|nickname)$/i;

  const is4xx = Array.isArray(s.expectation.expectedStatus)
    && s.expectation.expectedStatus.every(c => c >= 400);

  for (const path of Object.keys(checks)) {
    if (!uniquePathRe.test(path)) continue;

    // For tests that expect only 4xx (error responses): remove assertions on data fields
    // because the API won't return the created resource.
    if (is4xx) {
      delete checks[path];
      continue;
    }

    // For 2xx tests: ensure assertion value matches the body field value so they use the
    // same {{tcUniqueId}} expansion. Determine body field name from the path tail.
    const fieldMatch = path.match(/([\w_]+)$/i);
    if (!fieldMatch) continue;
    const fieldName = Object.keys(bodyFields).find(
      k => k.toLowerCase() === fieldMatch[1].toLowerCase()
    );
    if (fieldName && typeof bodyFields[fieldName] === 'string') {
      checks[path] = bodyFields[fieldName];
    } else {
      // No matching body field — apply patchBodyForUniqueness logic to the assertion value
      const curVal = checks[path];
      if (typeof curVal === 'string') {
        checks[path] = patchBodyForUniqueness(JSON.stringify({ _v: curVal })).replace(/^\{"_v":"?|"?\}$/g, '') || curVal;
      }
    }
  }

  // Remove empty jsonPathChecks
  if (Object.keys(checks).length === 0) s.expectation.jsonPathChecks = null;
}
scenarios.forEach(syncJsonPathChecks);

return [{
  json: {
    scenarios,
    model:      parsed.model      ?? 'unknown',
    tokensUsed: parsed.tokensUsed ?? 0
  }
}];
